// Define a Car class blueprint
class Car {
    // Fields: data each Car object will have
    String model;
    int year;
    double price;

    // Method: behavior this car can perform
    void displayInfo() {
        System.out.println(model + " (" + year + ") - $" + price);
    }
}

public class Main {
    public static void main(String[] args) {
        // Create two actual Car objects from the blueprint
        Car car1 = new Car();
        car1.model = "Camry";
        car1.year = 2023;
        car1.price = 28000.00;

        Car car2 = new Car();
        car2.model = "Civic";
        car2.year = 2024;
        car2.price = 25500.00;

        car1.displayInfo();
        car2.displayInfo();
    }
}
// Expected output:
// Camry (2023) - $28000.0
// Civic (2024) - $25500.0
